@router.post("/attribute/group", summary="群体归因分析", tags=["A-归因分析"])
async def attribute_group(req: GroupAttributionRequest):
    """
    Level 2: 群体干预效果归因

    使用PSM+DRE+Bootstrap方法评估群体干预效果，
    包含完整的统计检验和敏感性分析。
    """
    try:
