    age: int
    gender: str = "未知"
    bmi: float = 22.0
    stress_level: str = "medium"
    sleep_hours: float = 7.0
    primary_issue: str = ""
    medical_history: str = ""
    systolic_bp: int = 120
    diastolic_bp: int = 80
    fasting_glucose: float = 5.0

@router.post("/")
def create_patient(data: PatientCreate):
    return add_patient(**data.model_dump())

@router.get("/")
def get_all_patients():
    return list_patients()

